script.text:
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', null, 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;&ExportActiveVoucher;
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  if (f._usedDP) {
    f._gridDP = f.getItem('p&Tag;')._controlBehavior;
    f._gridDP.add_onRender(on$Voucher$GridDownPaymentRender);
  }
  if (!f._printList) setFormHiddenPrintListFields(f);
      &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
      &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&VoucherLogHandleStatus;
}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._usedDP) try {f._gridDP.remove_onRender(on$Voucher$GridDownPaymentRender);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d21')._controlBehavior;
  switch (action) {
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      if (f._usedDP) {
        f._gridDP.setSequenceNumber('line_nbr');
        f._gridDP.setContinuance('stt_rec0');
      }
      break;
    case 'Explore':
    &CancelStatusExplore;
    &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function setFormHiddenPrintListFields(f) {
  var a = ['so_bk', 'ngay_bk'];
  for (var i = 0; i < a.length; i++) {
    $common.setVisible(f.getItem(a[i]).parentNode.parentNode.parentNode, false);
  }
}
/* </flatten> */
      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d21')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt2,t_thue_nt,t_tt_nt,t_ck_nt:t_tien2,t_thue,t_tt,t_ck');
    if (!f._udfQuantityPrice) v.addGridFields(g, 'tien_nt2,ck_nt,thue_nt:tien2,ck,thue');
      else v.addGridFields(g, 'gia_nt,tien_nt2,ck_nt,thue_nt:gia,tien2,ck,thue');
    v.addTotalFields(g, [['t_tien_nt2', 'tien_nt2'],['t_tien2', 'tien2'],['t_thue_nt', 'thue_nt'],['t_thue', 'thue'], ['t_ck_nt', 'ck_nt'], ['t_ck', 'ck']]);
    v.set_referenceFields(null);
    v.set_executeExpression(['[t_tt_nt]:=[t_tien_nt2] - [t_ck_nt]+[t_thue_nt]', '[t_tt]:=[t_tien2] - [t_ck]+[t_thue]']);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    var f = sender.get_element().parentForm;
    if (e.object._baseCurrency == e.type) {
      focus$Voucher$Tab(f, true);
      &PostCurrencySelected;
    }
    if (f._usedDP) set$Voucher$GridColumns(f._gridDP);
  }
}


function onChange$Voucher$Tab(sender, e) {focus$Voucher$Tab(sender.parentForm);&PostTabFocus;}
function focus$Voucher$Tab(f, force) {
  var c = 'tk_thue_no', a = force ? [['d21', c]] : ['d21'];
&ExportFocusVoucherTab;
  if (f._usedDP) Array.add(a, force ? ['p21', c] : 'p21');
  if (f._usedEI) Array.add(a, 'sd_hddt_yn');
  &ListTabChange;
  &PostTabChange;
  Array.add(a, 'ten_khthue');
  f.focusWhenTabChanged(a);
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$DebitAccount(o) {o.parentForm.request('DebitAccount', 'DebitAccount', ['tk'], o);}
function onChange$Voucher$Memo(o) {
  var g = o.parentForm.getItem("d21")._controlBehavior;
  if ((o.parentForm._action == 'New') && (g._rowCount > 0) && (g._getItemValue(1, g._getColumnOrder('dien_giai')) == ''))
  g._getItem(1, g._getColumnOrder('dien_giai')).value = o.value;
}
/* </flatten> */


function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('tk_thue_no', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ma_tt', result[2].Value, result[3].Value, &ResetCustInfoFields;);
      f.setItemControlBehavior('ten_khthue', result[4].Value, null, true);
      f.setItemControlBehavior('ong_ba', result[5].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('dia_chithue', result[6].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_so_thue', result[7].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_nvbh', result[8].Value, result[9].Value, &ResetCustInfoFields;);
      &EICustomerResponseComplete;
      f.live(f.getItem('ong_ba'));
      break;
    case 'DebitAccount':
      f.setItemControlBehavior('tk_thue_no', result[0].Value, '');
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    &EIResponseCompleteChecking;
    default:
      break;
  }
}

      &DPScript;
      &ListScript;
      &PostScript;

