if exists(select 1 from dmkh where ma_kh = @ma_kh and (kh_yn = 1 or nv_yn = 1)) begin
  &EICustomerResponseExists;
  select rtrim(a.tk) as tk, b.ten_tk%l, rtrim(a.ma_tt) as ma_tt, c.ten_tt%l, rtrim(a.ten_kh) as ten_kh, rtrim(doi_tac) as ong_ba, rtrim(a.dia_chi) as dia_chi, rtrim(a.ma_so_thue) as ma_so_thue, rtrim(a.ma_nvbh) as ma_nvbh, d.ten_nvbh%l&EICustomerResponseValue;
    from dmkh a left join dmtk b on a.tk = b.tk left join dmtt c on a.ma_tt = c.ma_tt left join dmnvbh d on a.ma_nvbh = d.ma_nvbh
    where a.ma_kh = @ma_kh
  return
end







